	/**
	 * Gets handle to the already created WebSocket or creates a new one if it does not alread exist
	 * @returns {Promise<?WebSocket>}
	 */
	const _createSocketConnection = async () => {
		if (!isOnline) return null;
		if (!accessToken) return null;
		if (webSocketRef.current?.readyState === 1 && checkIfAccessTokenIsAlive()) return webSocketRef.current; //a previously created WS connection is still alive / open

		const wsUrlFetchResp_raw = await fetch('https://api.upstox.com/v2/feed/market-data-feed/authorize', {
			method: 'GET',
			headers: {
				Accept: 'application/json',
				Authorization: 'Bearer ' + accessToken,
			},
		});
		const wsUrlFetchResp = await wsUrlFetchResp_raw.json();

		if (!Object.prototype.hasOwnProperty.call(wsUrlFetchResp, 'status')) return null;
		if (wsUrlFetchResp.status !== 'success') return null;
		if (!Object.prototype.hasOwnProperty.call(wsUrlFetchResp, 'data')) return null;
		if (!Object.prototype.hasOwnProperty.call(wsUrlFetchResp.data, 'authorized_redirect_uri')) return null;
		const wsUrl = wsUrlFetchResp.data.authorized_redirect_uri;

		return new Promise((resolve, reject) => {
			if (!isOnline) return reject(null);
			if (!accessToken) return reject(null);
			try {
				//if (webSocketRef.current?.readyState === 1) resolve(webSocketRef.current); //a previously created WS connection is still alive / open
				///// fetch websocket URL

				const socket = new WebSocket(wsUrl); //always prefer wss://
				socket.onopen = () => {
					setIsAlive(true); //since it has just been opened
					webSocketRef.current = socket;
					// console.log('Socket connection established')
					//_startLifeTimer();

					// //here start heartbeat
					// webSocketRef.current.send('ping');
					// heartbeatIntervalRef.current && clearInterval(heartbeatIntervalRef.current);
					// heartbeatIntervalRef.current = setInterval(() => {
					// 	//if (webSocketRef.current?.readyState === WebSocket.OPEN) {
					// 	if (webSocketRef.current?.readyState === 1) {
					// 		webSocketRef.current.send('ping');
					// 	}
					// }, 29000); // 29 seconds in milliseconds

					/////
					resolve(socket);
				};
				socket.onclose = (e) => {
					// eslint-disable-line no-unused-vars -- we haven't used the 'event' obj available to us
					// if(e.wasClean){
					// 	//console.log(`[close] Connection closed cleanly, code=${e.code} reason=${e.reason}`);
					// } else {
					// 	// e.g. server process killed or network down | event.code is usually 1006 in this case
					// 	//console.error('[close] Connection died');
					// 	//here we try reconnecting after setInterval
					// }
					setIsAlive(false);
					// setTick(0);
					webSocketRef.current = null;
					//clearTimeout(wsLifeTimer);
					// //here stop heartbeat
					// clearInterval(heartbeatIntervalRef.current);
					reject(null);
				};
				socket.onerror = () => {
					if (socket.readyState !== 1) {
						//meaning socket is not open	//https://developer.mozilla.org/en-US/docs/Web/API/WebSocket/readyState
						setIsAlive(false);
						// setTick(0);
						webSocketRef.current = null;
						// clearInterval(heartbeatIntervalRef.current);
					}
					// reject();
				};
				socket.onmessage = (e) => {
					setIsAlive(true);
					//_extendLifeTimeout();	// here we clear setTimeout that resets 'isAlive' to false
					__doOnWebSocketResponse(e.data);
				};
				//webSocketRef.current = socket;
			} catch (err) {
				// console.error(err);
				setIsAlive(false);
				reject(null);
			}
		});
	};

	const closeSocketConnection = () => {
		webSocketRef.current?.close();
		webSocketRef.current = null;
		setIsAlive(false); //although this is handled in onclose event of websocket, we do it here too
		// //shut down the heart-beat timer
		// clearInterval(heartbeatIntervalRef.current);
	};

	// const __doOnWebSocketResponse = (respData) => {
	// 	//console.log(`WS resp type: ${respData.constructor.name}`);
